INSERT INTO ordena_frases (subject_id, level, grades, sentence) VALUES
('biologia', 'bachillerato', '{1}', 'Los bioelementos primarios como el carbono hidrógeno oxígeno y nitrógeno constituyen más del noventa y seis por ciento de la materia viva'),
('biologia', 'bachillerato', '{1}', 'El agua actúa como disolvente universal en los seres vivos gracias a su elevada polaridad y capacidad para formar puentes de hidrógeno'),
('biologia', 'bachillerato', '{1}', 'Los lípidos son biomoléculas insolubles en agua que cumplen funciones de reserva energética estructural y reguladora'),
('biologia', 'bachillerato', '{1}', 'La membrana plasmática está compuesta por una bicapa lipídica con proteínas integrales y periféricas según el modelo de mosaico fluido'),
('biologia', 'bachillerato', '{1}', 'Los ácidos nucleicos son polímeros de nucleótidos que almacenan y transmiten la información genética de los seres vivos'),
('biologia', 'bachillerato', '{1}', 'El retículo endoplasmático rugoso presenta ribosomas adheridos a su membrana y participa en la síntesis de proteínas de secreción'),
('biologia', 'bachillerato', '{1}', 'El aparato de Golgi recibe proteínas del retículo endoplasmático las modifica empaqueta y distribuye a su destino celular'),
('biologia', 'bachillerato', '{1}', 'Los lisosomas son orgánulos con enzimas hidrolíticas que degradan macromoléculas y eliminan orgánulos dañados mediante autofagia'),
('biologia', 'bachillerato', '{1}', 'Los glúcidos se clasifican en monosacáridos disacáridos oligosacáridos y polisacáridos según el número de unidades monoméricas'),
('biologia', 'bachillerato', '{1}', 'La glucosa es un monosacárido de seis carbonos que constituye la principal fuente de energía para las células del organismo'),
('biologia', 'bachillerato', '{1}', 'Los polisacáridos de reserva como el glucógeno y el almidón almacenan energía mientras que la celulosa cumple función estructural'),
('biologia', 'bachillerato', '{1}', 'Las enzimas son proteínas con función catalítica que aceleran las reacciones bioquímicas disminuyendo la energía de activación necesaria'),
('biologia', 'bachillerato', '{1}', 'La especificidad enzimática se explica por el modelo de encaje inducido donde el sustrato modifica la conformación del centro activo'),
('biologia', 'bachillerato', '{1}', 'La estructura primaria de una proteína es la secuencia lineal de aminoácidos unidos por enlaces peptídicos en la cadena polipeptídica'),
('biologia', 'bachillerato', '{1}', 'La estructura terciaria de una proteína determina su forma tridimensional y depende de interacciones entre las cadenas laterales de aminoácidos'),
('biologia', 'bachillerato', '{1}', 'La desnaturalización proteica consiste en la pérdida de la estructura tridimensional por cambios de temperatura pH o agentes químicos'),
('biologia', 'bachillerato', '{1}', 'El citoesqueleto es una red de filamentos proteicos que mantiene la forma celular y participa en el movimiento y la división'),
('biologia', 'bachillerato', '{1}', 'Los microtúbulos son estructuras cilíndricas formadas por tubulina que constituyen el huso mitótico y los cilios y flagelos'),
('biologia', 'bachillerato', '{1}', 'Las mitocondrias poseen doble membrana y su propio ADN circular lo que apoya la teoría endosimbiótica de Lynn Margulis'),
('biologia', 'bachillerato', '{1}', 'La glucólisis es una ruta metabólica que degrada la glucosa en dos moléculas de piruvato produciendo ATP y NADH en el citoplasma'),
('biologia', 'bachillerato', '{1}', 'La respiración celular aerobia comprende la glucólisis el ciclo de Krebs y la cadena de transporte de electrones acoplada a fosforilación oxidativa'),
('biologia', 'bachillerato', '{1}', 'La fermentación es un proceso anaerobio que permite obtener energía a partir de la glucosa sin utilizar oxígeno como aceptor final'),
('biologia', 'bachillerato', '{1}', 'La fermentación láctica convierte el piruvato en lactato y se produce en células musculares cuando el aporte de oxígeno es insuficiente'),
('biologia', 'bachillerato', '{1}', 'La fermentación alcohólica transforma el piruvato en etanol y dióxido de carbono y es utilizada por levaduras en la producción de pan y vino'),
('biologia', 'bachillerato', '{1}', 'La fase luminosa de la fotosíntesis ocurre en los tilacoides del cloroplasto donde la luz excita electrones de la clorofila'),
('biologia', 'bachillerato', '{1}', 'La fase oscura de la fotosíntesis o ciclo de Calvin tiene lugar en el estroma del cloroplasto y fija el dióxido de carbono'),
('biologia', 'bachillerato', '{1}', 'Los cloroplastos poseen doble membrana tilacoides con pigmentos fotosintéticos y estroma donde se realiza la fijación del carbono'),
('biologia', 'bachillerato', '{1}', 'El ADN tiene estructura de doble hélice antiparalela con bases complementarias adenina-timina y guanina-citosina unidas por puentes de hidrógeno'),
('biologia', 'bachillerato', '{1}', 'El ARN mensajero transporta la información genética del núcleo a los ribosomas donde se traduce en una secuencia de aminoácidos'),
('biologia', 'bachillerato', '{1}', 'El ARN de transferencia lleva aminoácidos específicos al ribosoma reconociendo los codones del ARN mensajero mediante su anticodón'),
('biologia', 'bachillerato', '{1}', 'La transcripción es el proceso por el cual la ARN polimerasa sintetiza una molécula de ARN a partir de un molde de ADN'),
('biologia', 'bachillerato', '{1}', 'La traducción se realiza en los ribosomas donde la secuencia de codones del ARN mensajero se convierte en una cadena polipeptídica'),
('biologia', 'bachillerato', '{1}', 'El código genético es degenerado porque varios codones diferentes pueden codificar el mismo aminoácido en la síntesis de proteínas'),
('biologia', 'bachillerato', '{1}', 'La meiosis es una división celular que reduce a la mitad el número de cromosomas y genera gametos con variabilidad genética'),
('biologia', 'bachillerato', '{1}', 'En la profase I de la meiosis los cromosomas homólogos se aparean y pueden intercambiar fragmentos mediante el sobrecruzamiento'),
('biologia', 'bachillerato', '{1}', 'El sobrecruzamiento durante la meiosis aumenta la variabilidad genética al recombinar alelos entre cromátidas de cromosomas homólogos'),
('biologia', 'bachillerato', '{1}', 'Las fases de la mitosis son profase metafase anafase y telofase seguidas de la citocinesis que divide el citoplasma'),
('biologia', 'bachillerato', '{1}', 'El centrosoma organiza los microtúbulos del huso mitótico que separan los cromosomas durante la división celular'),
('biologia', 'bachillerato', '{1}', 'Los cromosomas están formados por cromatina que es la asociación de ADN con proteínas histonas empaquetadas en nucleosomas'),
('biologia', 'bachillerato', '{1}', 'El ciclo celular comprende la interfase con las fases G1 S y G2 seguida de la fase M de mitosis y citocinesis'),
('biologia', 'bachillerato', '{1}', 'Durante la fase S de la interfase se produce la replicación del ADN para que cada célula hija reciba una copia completa'),
('biologia', 'bachillerato', '{1}', 'El tejido epitelial recubre superficies corporales y cavidades internas y carece de vasos sanguíneos propios'),
('biologia', 'bachillerato', '{1}', 'El tejido conectivo incluye variedades como el cartilaginoso el óseo el adiposo y el sanguíneo con funciones de soporte y protección'),
('biologia', 'bachillerato', '{1}', 'El tejido muscular estriado esquelético se contrae voluntariamente gracias a la interacción de los filamentos de actina y miosina'),
('biologia', 'bachillerato', '{1}', 'El tejido nervioso está formado por neuronas que transmiten impulsos eléctricos y células gliales que les proporcionan soporte y nutrición'),
('biologia', 'bachillerato', '{1}', 'Las sales minerales participan en funciones reguladoras como el mantenimiento del pH y la presión osmótica de los fluidos corporales'),
('biologia', 'bachillerato', '{1}', 'Los oligoelementos como el hierro el zinc y el cobre son esenciales en pequeñas cantidades para la actividad enzimática celular'),
('biologia', 'bachillerato', '{1}', 'Las vitaminas son moléculas orgánicas que actúan como coenzimas y se necesitan en cantidades mínimas para el correcto funcionamiento metabólico'),
('biologia', 'bachillerato', '{1}', 'Los fosfolípidos tienen una cabeza polar hidrófila y dos colas apolares hidrófobas lo que les permite formar bicapas en medio acuoso'),
('biologia', 'bachillerato', '{1}', 'El colesterol es un lípido insaponificable que modula la fluidez de la membrana plasmática y es precursor de hormonas esteroideas'),
('biologia', 'bachillerato', '{1}', 'Los peroxisomas son orgánulos que contienen oxidasas y catalasas para degradar peróxido de hidrógeno y ácidos grasos de cadena larga'),
('biologia', 'bachillerato', '{1}', 'Las vacuolas vegetales almacenan agua sales y pigmentos y contribuyen al mantenimiento de la turgencia celular'),
('biologia', 'bachillerato', '{1}', 'La pared celular vegetal está compuesta principalmente por celulosa y confiere rigidez y protección a la célula vegetal'),
('biologia', 'bachillerato', '{1}', 'Los plasmodesmos son canales citoplasmáticos que atraviesan la pared celular y comunican células vegetales adyacentes'),
('biologia', 'bachillerato', '{1}', 'La ósmosis es el paso de agua a través de una membrana semipermeable desde la solución menos concentrada hacia la más concentrada'),
('biologia', 'bachillerato', '{1}', 'El transporte activo requiere gasto de ATP para mover sustancias a través de la membrana en contra del gradiente de concentración'),
('biologia', 'bachillerato', '{1}', 'La endocitosis permite a la célula incorporar partículas grandes englobándolas con la membrana plasmática y formando vesículas internas'),
('biologia', 'bachillerato', '{1}', 'La exocitosis es el proceso inverso por el cual vesículas intracelulares se fusionan con la membrana liberando su contenido al exterior'),
('biologia', 'bachillerato', '{1}', 'El metabolismo celular se divide en catabolismo que degrada moléculas liberando energía y anabolismo que sintetiza moléculas consumiéndola'),
('biologia', 'bachillerato', '{1}', 'El ATP es la molécula transportadora de energía más importante de la célula y se regenera mediante fosforilación a partir de ADP'),
('biologia', 'bachillerato', '{1}', 'La cadena de transporte de electrones mitocondrial genera un gradiente de protones que impulsa la síntesis de ATP por quimiósmosis'),
('biologia', 'bachillerato', '{1}', 'La beta-oxidación de los ácidos grasos produce acetil-CoA que ingresa en el ciclo de Krebs para su completa oxidación'),
('biologia', 'bachillerato', '{1}', 'Las hormonas vegetales como las auxinas regulan el crecimiento y desarrollo de las plantas en respuesta a estímulos ambientales'),
('biologia', 'bachillerato', '{1}', 'El meristemo apical es un tejido embrionario localizado en los extremos de tallos y raíces responsable del crecimiento en longitud'),
('biologia', 'bachillerato', '{1}', 'La savia bruta asciende por el xilema desde las raíces hasta las hojas impulsada por la transpiración y la cohesión del agua'),
('biologia', 'bachillerato', '{1}', 'La savia elaborada se transporta por el floema desde los órganos fotosintéticos hasta los tejidos que necesitan nutrientes orgánicos'),
('biologia', 'bachillerato', '{1}', 'Los estomas son poros en la epidermis foliar que regulan el intercambio de gases y la pérdida de agua por transpiración'),
('biologia', 'bachillerato', '{1}', 'La célula procariota carece de orgánulos membranosos y su material genético se encuentra en una región denominada nucleoide'),
('biologia', 'bachillerato', '{1}', 'Los ribosomas están formados por dos subunidades de ARN ribosómico y proteínas y son el lugar donde se sintetizan las proteínas'),
('biologia', 'bachillerato', '{1}', 'La difusión facilitada utiliza proteínas transportadoras o canales para permitir el paso de moléculas polares a través de la membrana'),
('biologia', 'bachillerato', '{1}', 'Los ácidos grasos insaturados presentan dobles enlaces en su cadena hidrocarbonada lo que les confiere mayor fluidez a temperatura ambiente'),
('biologia', 'bachillerato', '{1}', 'La sacarosa es un disacárido formado por la unión de una molécula de glucosa y una de fructosa mediante un enlace glucosídico'),
('biologia', 'bachillerato', '{1}', 'Los aminoácidos esenciales no pueden ser sintetizados por el organismo y deben incorporarse a través de la dieta alimentaria'),
('biologia', 'bachillerato', '{1}', 'La hemoglobina es una proteína con estructura cuaternaria formada por cuatro subunidades cada una con un grupo hemo que transporta oxígeno'),
('biologia', 'bachillerato', '{1}', 'Los centriolos son estructuras cilíndricas de microtúbulos que intervienen en la formación del huso acromático durante la división celular'),
('biologia', 'bachillerato', '{1}', 'La cromatina se condensa en cromosomas visibles durante la división celular facilitando la correcta segregación del material genético'),
('biologia', 'bachillerato', '{1}', 'El nucleolo es una región del núcleo donde se sintetiza el ARN ribosómico y se ensamblan las subunidades ribosómicas'),
('biologia', 'bachillerato', '{1}', 'La envoltura nuclear está atravesada por poros que regulan el intercambio de moléculas entre el núcleo y el citoplasma'),
('biologia', 'bachillerato', '{1}', 'Los inhibidores enzimáticos competitivos se unen al centro activo de la enzima compitiendo con el sustrato por el mismo sitio'),
('biologia', 'bachillerato', '{1}', 'Los cofactores son iones metálicos o moléculas orgánicas necesarios para que algunas enzimas puedan ejercer su función catalítica'),
('biologia', 'bachillerato', '{1}', 'La regulación alostérica de enzimas permite activar o inhibir su actividad mediante la unión de moduladores a sitios diferentes del activo'),
('biologia', 'bachillerato', '{1}', 'El retículo endoplasmático liso carece de ribosomas y participa en la síntesis de lípidos y la detoxificación celular'),
('biologia', 'bachillerato', '{1}', 'La teoría celular establece que todos los seres vivos están formados por células y que toda célula proviene de otra preexistente'),
('biologia', 'bachillerato', '{1}', 'Las uniones celulares como los desmosomas y las uniones estrechas mantienen la cohesión y comunicación entre células de un tejido'),
('biologia', 'bachillerato', '{1}', 'El glucocálix es una cubierta de oligosacáridos en la superficie celular que participa en el reconocimiento entre células'),
('biologia', 'bachillerato', '{1}', 'La apoptosis es un proceso de muerte celular programada que elimina células dañadas o innecesarias de forma controlada'),
('biologia', 'bachillerato', '{1}', 'Los pigmentos fotosintéticos accesorios como los carotenoides amplían el rango de longitudes de onda absorbidas por la planta'),
('biologia', 'bachillerato', '{1}', 'El fotosistema II libera oxígeno al descomponer moléculas de agua mediante fotólisis en la fase luminosa de la fotosíntesis'),
('biologia', 'bachillerato', '{1}', 'La gluconeogénesis es la ruta metabólica que permite sintetizar glucosa a partir de precursores no glucídicos como el piruvato'),
('biologia', 'bachillerato', '{1}', 'Los genes se expresan de forma diferencial según el tipo celular lo que explica la diversidad de tejidos en un organismo pluricelular'),
('biologia', 'bachillerato', '{1}', 'El tejido muscular cardíaco presenta células ramificadas con discos intercalares que permiten la contracción sincronizada del corazón'),
('biologia', 'bachillerato', '{1}', 'La respiración anaerobia utiliza aceptores finales de electrones distintos del oxígeno como el nitrato o el sulfato en ciertos microorganismos');
INSERT INTO ordena_frases (subject_id, level, grades, sentence) VALUES
('biologia', 'bachillerato', '{2}', 'Las bacterias se reproducen asexualmente por fisión binaria y pueden intercambiar material genético mediante conjugación transducción y transformación'),
('biologia', 'bachillerato', '{2}', 'Los virus son parásitos intracelulares obligados que necesitan la maquinaria celular del hospedador para replicar su material genético'),
('biologia', 'bachillerato', '{2}', 'El ciclo lítico viral culmina con la lisis de la célula hospedadora y la liberación de nuevas partículas víricas al medio'),
('biologia', 'bachillerato', '{2}', 'El ciclo lisogénico implica la integración del genoma viral en el cromosoma bacteriano donde permanece latente como profago'),
('biologia', 'bachillerato', '{2}', 'Los retrovirus poseen ARN como material genético y utilizan la enzima transcriptasa inversa para sintetizar ADN a partir de su ARN'),
('biologia', 'bachillerato', '{2}', 'Los priones son agentes infecciosos compuestos exclusivamente por proteínas mal plegadas que provocan enfermedades neurodegenerativas'),
('biologia', 'bachillerato', '{2}', 'La tinción de Gram permite clasificar las bacterias en grampositivas con pared gruesa de peptidoglucano y gramnegativas con pared delgada'),
('biologia', 'bachillerato', '{2}', 'Las bacterias poseen plásmidos que son moléculas circulares de ADN extracromosómico con genes que confieren ventajas como la resistencia a antibióticos'),
('biologia', 'bachillerato', '{2}', 'Los antibióticos son sustancias producidas por microorganismos que inhiben el crecimiento o destruyen otras bacterias actuando sobre dianas específicas'),
('biologia', 'bachillerato', '{2}', 'La resistencia a los antibióticos surge por selección natural de bacterias portadoras de genes de resistencia en sus cromosomas o plásmidos'),
('biologia', 'bachillerato', '{2}', 'El sistema inmunitario innato proporciona una respuesta rápida e inespecífica mediante barreras físicas químicas y células fagocíticas'),
('biologia', 'bachillerato', '{2}', 'El sistema inmunitario adaptativo genera una respuesta específica y con memoria frente a cada antígeno mediante linfocitos T y B'),
('biologia', 'bachillerato', '{2}', 'Los linfocitos T citotóxicos reconocen y destruyen células infectadas o tumorales presentando antígenos en su superficie con moléculas MHC de clase I'),
('biologia', 'bachillerato', '{2}', 'Los linfocitos T colaboradores activan a los linfocitos B y a los macrófagos liberando citoquinas que coordinan la respuesta inmunitaria'),
('biologia', 'bachillerato', '{2}', 'La memoria inmunológica permite una respuesta más rápida e intensa ante una segunda exposición al mismo antígeno gracias a linfocitos de memoria'),
('biologia', 'bachillerato', '{2}', 'Las vacunas contienen antígenos atenuados o inactivados que estimulan la producción de anticuerpos y generan memoria inmunológica sin causar enfermedad'),
('biologia', 'bachillerato', '{2}', 'La sueroterapia consiste en administrar suero con anticuerpos preformados para proporcionar una inmunidad pasiva e inmediata pero temporal'),
('biologia', 'bachillerato', '{2}', 'Las enfermedades autoinmunes se producen cuando el sistema inmunitario ataca por error a las propias células y tejidos del organismo'),
('biologia', 'bachillerato', '{2}', 'Las alergias son respuestas inmunitarias exageradas frente a sustancias inocuas llamadas alérgenos que provocan la liberación de histamina'),
('biologia', 'bachillerato', '{2}', 'La inmunodeficiencia puede ser congénita por defectos genéticos o adquirida como en el caso de la infección por el virus VIH'),
('biologia', 'bachillerato', '{2}', 'El rechazo de trasplantes se produce cuando el sistema inmunitario del receptor reconoce como extrañas las moléculas del tejido trasplantado'),
('biologia', 'bachillerato', '{2}', 'La primera ley de Mendel o principio de uniformidad establece que los híbridos de la primera generación son todos iguales entre sí'),
('biologia', 'bachillerato', '{2}', 'La segunda ley de Mendel o principio de segregación indica que los alelos se separan durante la formación de los gametos'),
('biologia', 'bachillerato', '{2}', 'La tercera ley de Mendel o principio de combinación independiente establece que los genes de distintos cromosomas se heredan por separado'),
('biologia', 'bachillerato', '{2}', 'La herencia ligada al sexo se refiere a genes situados en los cromosomas sexuales como el daltonismo y la hemofilia en el cromosoma X'),
('biologia', 'bachillerato', '{2}', 'La codominancia ocurre cuando ambos alelos se expresan simultáneamente en el heterocigoto como en el sistema de grupos sanguíneos AB'),
('biologia', 'bachillerato', '{2}', 'Los genes ligados se encuentran en el mismo cromosoma y tienden a heredarse juntos salvo que el sobrecruzamiento los separe'),
('biologia', 'bachillerato', '{2}', 'La epistasia es la interacción génica en la que un gen enmascara o modifica la expresión fenotípica de otro gen no alélico'),
('biologia', 'bachillerato', '{2}', 'La herencia poligénica se produce cuando varios genes contribuyen de forma aditiva a un carácter como la estatura o el color de piel'),
('biologia', 'bachillerato', '{2}', 'Un organismo transgénico contiene en su genoma uno o más genes procedentes de otra especie introducidos mediante ingeniería genética'),
('biologia', 'bachillerato', '{2}', 'La clonación reproductiva consiste en obtener un organismo genéticamente idéntico a otro mediante transferencia nuclear a un óvulo enucleado'),
('biologia', 'bachillerato', '{2}', 'La electroforesis en gel permite separar fragmentos de ADN según su tamaño al migrar a través de un campo eléctrico'),
('biologia', 'bachillerato', '{2}', 'Los vectores de clonación como los plásmidos bacterianos se utilizan para introducir genes foráneos en células hospedadoras'),
('biologia', 'bachillerato', '{2}', 'La terapia génica busca corregir enfermedades hereditarias introduciendo copias funcionales de genes defectuosos en las células del paciente'),
('biologia', 'bachillerato', '{2}', 'La tecnología CRISPR-Cas9 permite editar el genoma con precisión cortando el ADN en secuencias específicas y añadiendo o eliminando genes'),
('biologia', 'bachillerato', '{2}', 'Los marcadores genéticos son secuencias de ADN con posición cromosómica conocida que permiten identificar individuos y rastrear la herencia'),
('biologia', 'bachillerato', '{2}', 'El proyecto Genoma Humano logró secuenciar los aproximadamente tres mil millones de pares de bases del ADN de nuestra especie'),
('biologia', 'bachillerato', '{2}', 'Las células madre son células indiferenciadas capaces de autorrenovarse y diferenciarse en tipos celulares especializados del organismo'),
('biologia', 'bachillerato', '{2}', 'La huella genética o perfil de ADN se obtiene analizando regiones polimórficas del genoma y se usa en medicina forense y pruebas de paternidad'),
('biologia', 'bachillerato', '{2}', 'Los organismos genéticamente modificados se emplean en agricultura para obtener variedades resistentes a plagas sequía o herbicidas'),
('biologia', 'bachillerato', '{2}', 'La bioética analiza los dilemas morales derivados de los avances biotecnológicos como la clonación y la manipulación genética'),
('biologia', 'bachillerato', '{2}', 'Los niveles tróficos de un ecosistema son productores consumidores primarios consumidores secundarios y descomponedores'),
('biologia', 'bachillerato', '{2}', 'La productividad primaria neta es la cantidad de materia orgánica que los productores acumulan después de descontar su propia respiración'),
('biologia', 'bachillerato', '{2}', 'La sucesión ecológica es el proceso de cambio gradual de la comunidad biológica de un ecosistema a lo largo del tiempo'),
('biologia', 'bachillerato', '{2}', 'Las pirámides ecológicas representan gráficamente la distribución de biomasa energía o número de individuos en cada nivel trófico'),
('biologia', 'bachillerato', '{2}', 'El ciclo del carbono incluye la fijación por fotosíntesis la liberación por respiración y combustión y el almacenamiento en carbonatos'),
('biologia', 'bachillerato', '{2}', 'El ciclo del nitrógeno comprende la fijación biológica la nitrificación la asimilación vegetal la amonificación y la desnitrificación'),
('biologia', 'bachillerato', '{2}', 'El efecto invernadero se intensifica por la emisión excesiva de gases como el dióxido de carbono y el metano de origen antropogénico'),
('biologia', 'bachillerato', '{2}', 'La eutrofización de lagos y ríos se produce por el exceso de nutrientes como nitratos y fosfatos que favorecen la proliferación de algas'),
('biologia', 'bachillerato', '{2}', 'La lluvia ácida se forma cuando los óxidos de azufre y nitrógeno emitidos por la industria reaccionan con el vapor de agua atmosférico'),
('biologia', 'bachillerato', '{2}', 'La capa de ozono estratosférico protege a los seres vivos de la radiación ultravioleta y se degrada por los compuestos clorofluorocarbonados'),
('biologia', 'bachillerato', '{2}', 'Las relaciones interespecíficas como el mutualismo el parasitismo y la competencia regulan las poblaciones dentro de una comunidad'),
('biologia', 'bachillerato', '{2}', 'La especiación alopátrica ocurre cuando una barrera geográfica aísla poblaciones que divergen genéticamente hasta formar especies distintas'),
('biologia', 'bachillerato', '{2}', 'Las pruebas de la evolución incluyen los registros fósiles la anatomía comparada la embriología y las homologías moleculares'),
('biologia', 'bachillerato', '{2}', 'La deriva genética es un cambio aleatorio en las frecuencias alélicas de una población especialmente importante en poblaciones pequeñas'),
('biologia', 'bachillerato', '{2}', 'La ley de Hardy-Weinberg establece que las frecuencias alélicas permanecen constantes en una población grande sin mutación migración ni selección'),
('biologia', 'bachillerato', '{2}', 'Los órganos homólogos comparten origen embrionario pero pueden tener funciones diferentes como la aleta de una ballena y el brazo humano'),
('biologia', 'bachillerato', '{2}', 'Los órganos análogos tienen distinto origen pero función similar como las alas de un insecto y las de un ave resultado de convergencia evolutiva'),
('biologia', 'bachillerato', '{2}', 'Las mutaciones cromosómicas incluyen deleciones duplicaciones inversiones y translocaciones que alteran la estructura de los cromosomas'),
('biologia', 'bachillerato', '{2}', 'Las mutaciones genómicas como la trisomía del cromosoma veintiuno producen alteraciones en el número total de cromosomas del individuo'),
('biologia', 'bachillerato', '{2}', 'Los agentes mutagénicos como la radiación ultravioleta y ciertos compuestos químicos aumentan la frecuencia de mutaciones en el ADN'),
('biologia', 'bachillerato', '{2}', 'La regulación génica en procariotas se realiza mediante operones como el operón lac que se activa en presencia de lactosa'),
('biologia', 'bachillerato', '{2}', 'La regulación de la expresión génica en eucariotas incluye modificaciones epigenéticas como la metilación del ADN y la acetilación de histonas'),
('biologia', 'bachillerato', '{2}', 'Los microorganismos del suelo descomponen la materia orgánica reciclando nutrientes minerales que las plantas absorben por sus raíces'),
('biologia', 'bachillerato', '{2}', 'La simbiosis entre hongos micorrícicos y raíces vegetales favorece la absorción de fósforo y agua mejorando el crecimiento de la planta'),
('biologia', 'bachillerato', '{2}', 'Las bacterias nitrificantes del suelo oxidan el amonio a nitritos y luego a nitratos que son la forma asimilable por las plantas'),
('biologia', 'bachillerato', '{2}', 'Los biomas terrestres se distribuyen según la latitud y la altitud determinados principalmente por la temperatura y las precipitaciones'),
('biologia', 'bachillerato', '{2}', 'La fragmentación del hábitat reduce la biodiversidad al crear poblaciones aisladas más vulnerables a la extinción local'),
('biologia', 'bachillerato', '{2}', 'Los corredores ecológicos conectan áreas protegidas permitiendo el flujo genético entre poblaciones y reduciendo el aislamiento'),
('biologia', 'bachillerato', '{2}', 'Las especies invasoras alteran los ecosistemas nativos compitiendo con las especies autóctonas por los recursos disponibles'),
('biologia', 'bachillerato', '{2}', 'La biorremediación utiliza microorganismos para degradar contaminantes del suelo y el agua transformándolos en sustancias inocuas'),
('biologia', 'bachillerato', '{2}', 'La fermentación industrial emplea microorganismos para producir alimentos como yogur cerveza y queso así como fármacos como la insulina recombinante'),
('biologia', 'bachillerato', '{2}', 'Los microorganismos patógenos pueden causar enfermedades infecciosas al superar las barreras defensivas del organismo hospedador'),
('biologia', 'bachillerato', '{2}', 'La respuesta inflamatoria es un mecanismo de defensa innata que produce enrojecimiento calor hinchazón y dolor en la zona afectada'),
('biologia', 'bachillerato', '{2}', 'El complemento es un conjunto de proteínas plasmáticas que facilitan la fagocitosis y la lisis de microorganismos invasores'),
('biologia', 'bachillerato', '{2}', 'Los interferones son proteínas liberadas por células infectadas por virus que activan mecanismos de defensa en células vecinas'),
('biologia', 'bachillerato', '{2}', 'Las inmunoglobulinas se clasifican en cinco clases IgG IgA IgM IgD e IgE con funciones específicas en la respuesta inmunitaria'),
('biologia', 'bachillerato', '{2}', 'La reacción antígeno-anticuerpo puede provocar la precipitación aglutinación opsonización o neutralización del agente patógeno'),
('biologia', 'bachillerato', '{2}', 'La inmunidad activa natural se adquiere al superar una infección mientras que la activa artificial se obtiene mediante la vacunación'),
('biologia', 'bachillerato', '{2}', 'Los hongos son organismos eucariotas heterótrofos que se reproducen por esporas y obtienen nutrientes mediante digestión externa'),
('biologia', 'bachillerato', '{2}', 'Los protozoos son organismos unicelulares eucariotas que pueden causar enfermedades parasitarias como la malaria y la enfermedad del sueño'),
('biologia', 'bachillerato', '{2}', 'La variabilidad genética es la base de la evolución biológica y se genera por mutaciones recombinación meiótica y flujo génico'),
('biologia', 'bachillerato', '{2}', 'La selección artificial permite al ser humano elegir organismos con caracteres deseables para la reproducción mejorando razas y variedades'),
('biologia', 'bachillerato', '{2}', 'La biodiversidad genética se refiere a la variación en genes y genotipos dentro de una especie lo que aumenta su capacidad de adaptación'),
('biologia', 'bachillerato', '{2}', 'La conservación de la biodiversidad requiere estrategias como la creación de reservas naturales la protección legal y la educación ambiental'),
('biologia', 'bachillerato', '{2}', 'El desarrollo sostenible pretende compatibilizar el progreso económico con la conservación del medio ambiente para las generaciones futuras'),
('biologia', 'bachillerato', '{2}', 'Los indicadores biológicos como ciertos invertebrados acuáticos permiten evaluar la calidad ambiental de ríos y lagos'),
('biologia', 'bachillerato', '{2}', 'La bioinformática aplica herramientas computacionales al análisis de secuencias genómicas para comparar genes entre diferentes especies'),
('biologia', 'bachillerato', '{2}', 'La PCR cuantitativa permite medir la cantidad de un fragmento de ADN específico en una muestra mediante fluorescencia en tiempo real'),
('biologia', 'bachillerato', '{2}', 'Los anticuerpos monoclonales son inmunoglobulinas idénticas producidas por un único clon de linfocitos B con aplicaciones diagnósticas y terapéuticas'),
('biologia', 'bachillerato', '{2}', 'La metagenómica estudia el material genético de comunidades microbianas directamente del ambiente sin necesidad de cultivo en laboratorio'),
('biologia', 'bachillerato', '{2}', 'Los transposones son secuencias de ADN móviles que pueden cambiar de posición dentro del genoma alterando la expresión de genes cercanos'),
('biologia', 'bachillerato', '{2}', 'La filogenia molecular reconstruye las relaciones evolutivas entre organismos comparando secuencias de proteínas y ácidos nucleicos homólogos');
INSERT INTO ordena_frases (subject_id, level, grades, sentence) VALUES
('fisica', 'bachillerato', '{1}', 'La velocidad instantánea es el límite de la velocidad media cuando el intervalo de tiempo tiende a cero'),
('fisica', 'bachillerato', '{1}', 'La aceleración centrípeta en un movimiento circular apunta siempre hacia el centro de la circunferencia que describe el móvil'),
('fisica', 'bachillerato', '{1}', 'El movimiento rectilíneo uniformemente acelerado se caracteriza por tener aceleración constante y velocidad que varía linealmente con el tiempo'),
('fisica', 'bachillerato', '{1}', 'La posición de un móvil en tiro parabólico depende de la velocidad inicial y del ángulo de lanzamiento respecto a la horizontal'),
('fisica', 'bachillerato', '{1}', 'El alcance máximo de un proyectil lanzado desde el suelo se consigue con un ángulo de cuarenta y cinco grados respecto a la horizontal'),
('fisica', 'bachillerato', '{1}', 'El periodo de un movimiento circular uniforme es el tiempo que tarda el móvil en completar una vuelta completa a la circunferencia'),
('fisica', 'bachillerato', '{1}', 'La frecuencia de un movimiento circular es el número de vueltas completas que realiza el móvil por unidad de tiempo'),
('fisica', 'bachillerato', '{1}', 'La velocidad angular es el ángulo barrido por unidad de tiempo y se mide en radianes por segundo en el sistema internacional'),
('fisica', 'bachillerato', '{1}', 'La aceleración tangencial aparece cuando la velocidad angular varía y es responsable del cambio en el módulo de la velocidad'),
('fisica', 'bachillerato', '{1}', 'La composición de movimientos permite descomponer un movimiento complejo en sus componentes horizontal y vertical independientes'),
('fisica', 'bachillerato', '{1}', 'La primera ley de Newton establece que un cuerpo permanece en reposo o en movimiento rectilíneo uniforme si la fuerza neta es cero'),
('fisica', 'bachillerato', '{1}', 'La tercera ley de Newton afirma que toda acción tiene una reacción de igual magnitud y dirección pero de sentido contrario'),
('fisica', 'bachillerato', '{1}', 'El diagrama de cuerpo libre representa todas las fuerzas que actúan sobre un objeto aislado para aplicar las leyes de Newton'),
('fisica', 'bachillerato', '{1}', 'La fuerza de rozamiento cinético se opone al movimiento y es proporcional a la fuerza normal mediante el coeficiente de rozamiento'),
('fisica', 'bachillerato', '{1}', 'La fuerza de rozamiento estático impide que un cuerpo comience a moverse y su valor máximo es mayor que el rozamiento cinético'),
('fisica', 'bachillerato', '{1}', 'El momento lineal de un cuerpo es el producto de su masa por su velocidad y se conserva en sistemas aislados'),
('fisica', 'bachillerato', '{1}', 'El impulso de una fuerza es igual a la variación del momento lineal del cuerpo sobre el que actúa durante un intervalo de tiempo'),
('fisica', 'bachillerato', '{1}', 'En un choque elástico se conservan tanto el momento lineal como la energía cinética total del sistema de partículas'),
('fisica', 'bachillerato', '{1}', 'En un choque inelástico se conserva el momento lineal pero parte de la energía cinética se transforma en calor o deformación'),
('fisica', 'bachillerato', '{1}', 'La fuerza centrípeta es la fuerza neta dirigida hacia el centro que mantiene a un cuerpo describiendo una trayectoria circular'),
('fisica', 'bachillerato', '{1}', 'Un cuerpo en un plano inclinado experimenta la componente del peso paralela al plano que tiende a deslizarlo hacia abajo'),
('fisica', 'bachillerato', '{1}', 'La tensión en una cuerda ideal transmite la fuerza íntegramente de un extremo al otro sin pérdida cuando su masa es despreciable'),
('fisica', 'bachillerato', '{1}', 'La energía cinética de un cuerpo es la energía asociada a su movimiento y vale la mitad del producto de su masa por la velocidad al cuadrado'),
('fisica', 'bachillerato', '{1}', 'La energía potencial gravitatoria de un cuerpo cerca de la superficie terrestre es el producto de su masa por la gravedad por la altura'),
('fisica', 'bachillerato', '{1}', 'El teorema de las fuerzas vivas establece que el trabajo neto realizado sobre un cuerpo es igual a la variación de su energía cinética'),
('fisica', 'bachillerato', '{1}', 'La potencia mecánica es la rapidez con la que se realiza un trabajo y se mide en vatios o julios por segundo'),
('fisica', 'bachillerato', '{1}', 'Una fuerza conservativa es aquella cuyo trabajo no depende del camino recorrido sino solo de las posiciones inicial y final'),
('fisica', 'bachillerato', '{1}', 'La fuerza elástica de un muelle obedece la ley de Hooke y es proporcional al desplazamiento desde la posición de equilibrio'),
('fisica', 'bachillerato', '{1}', 'La energía potencial elástica almacenada en un muelle es la mitad del producto de la constante elástica por el cuadrado de la deformación'),
('fisica', 'bachillerato', '{1}', 'El movimiento armónico simple se produce cuando la fuerza restauradora es proporcional y opuesta al desplazamiento respecto al equilibrio'),
('fisica', 'bachillerato', '{1}', 'El periodo de un péndulo simple depende de la longitud del hilo y de la aceleración de la gravedad pero no de la masa'),
('fisica', 'bachillerato', '{1}', 'El periodo de un muelle oscilante depende de la masa del cuerpo y de la constante elástica del muelle'),
('fisica', 'bachillerato', '{1}', 'La ley de gravitación universal de Newton afirma que dos masas se atraen con una fuerza proporcional al producto de ambas'),
('fisica', 'bachillerato', '{1}', 'La intensidad del campo gravitatorio en la superficie terrestre es la aceleración que experimenta cualquier cuerpo en caída libre'),
('fisica', 'bachillerato', '{1}', 'La velocidad de escape es la velocidad mínima que debe tener un objeto para abandonar el campo gravitatorio de un planeta'),
('fisica', 'bachillerato', '{1}', 'Las leyes de Kepler describen las órbitas elípticas de los planetas la ley de áreas y la relación entre periodo y semieje mayor'),
('fisica', 'bachillerato', '{1}', 'La primera ley de Kepler establece que los planetas describen órbitas elípticas con el Sol situado en uno de los focos'),
('fisica', 'bachillerato', '{1}', 'La segunda ley de Kepler indica que el radio vector que une el planeta con el Sol barre áreas iguales en tiempos iguales'),
('fisica', 'bachillerato', '{1}', 'La tercera ley de Kepler relaciona el cuadrado del periodo orbital con el cubo del semieje mayor de la elipse'),
('fisica', 'bachillerato', '{1}', 'La energía potencial gravitatoria entre dos masas es negativa y aumenta acercándose a cero cuando la distancia tiende a infinito'),
('fisica', 'bachillerato', '{1}', 'Los satélites geoestacionarios orbitan a una altitud donde su periodo orbital coincide con el periodo de rotación de la Tierra'),
('fisica', 'bachillerato', '{1}', 'La ingravidez aparente en un satélite en órbita se debe a que el satélite y todo su contenido están en caída libre constante'),
('fisica', 'bachillerato', '{1}', 'La temperatura es una magnitud que mide la energía cinética media de las partículas que componen un sistema termodinámico'),
('fisica', 'bachillerato', '{1}', 'El calor es la transferencia de energía entre dos cuerpos a diferente temperatura hasta que alcanzan el equilibrio térmico'),
('fisica', 'bachillerato', '{1}', 'El calor específico es la cantidad de calor necesaria para elevar un grado la temperatura de un gramo de sustancia'),
('fisica', 'bachillerato', '{1}', 'El calor latente es la energía necesaria para que una sustancia cambie de estado sin variar su temperatura durante el proceso'),
('fisica', 'bachillerato', '{1}', 'La primera ley de la termodinámica establece que la variación de energía interna es igual al calor absorbido menos el trabajo realizado'),
('fisica', 'bachillerato', '{1}', 'Un proceso isotérmico ocurre a temperatura constante y en un gas ideal el trabajo realizado es igual al calor absorbido'),
('fisica', 'bachillerato', '{1}', 'Un proceso adiabático se produce sin intercambio de calor con el entorno y toda la energía se convierte en trabajo o energía interna'),
('fisica', 'bachillerato', '{1}', 'Un proceso isóbaro ocurre a presión constante y el trabajo realizado por el gas es el producto de la presión por la variación de volumen'),
('fisica', 'bachillerato', '{1}', 'Un proceso isócoro ocurre a volumen constante y todo el calor absorbido se convierte en variación de energía interna del gas'),
('fisica', 'bachillerato', '{1}', 'La segunda ley de la termodinámica afirma que el calor fluye espontáneamente del cuerpo caliente al frío y nunca al revés'),
('fisica', 'bachillerato', '{1}', 'El rendimiento de una máquina térmica es el cociente entre el trabajo producido y el calor absorbido del foco caliente'),
('fisica', 'bachillerato', '{1}', 'El ciclo de Carnot es el ciclo termodinámico más eficiente posible entre dos focos térmicos a temperaturas diferentes'),
('fisica', 'bachillerato', '{1}', 'La entropía de un sistema aislado nunca disminuye lo que establece la dirección natural de los procesos termodinámicos'),
('fisica', 'bachillerato', '{1}', 'La dilatación térmica lineal hace que los sólidos aumenten sus dimensiones de forma proporcional al incremento de temperatura'),
('fisica', 'bachillerato', '{1}', 'La transmisión de calor por conducción se produce por contacto directo entre partículas de un sólido sin desplazamiento de materia'),
('fisica', 'bachillerato', '{1}', 'La transmisión de calor por convección implica el movimiento de masas de fluido caliente que transfieren energía al desplazarse'),
('fisica', 'bachillerato', '{1}', 'La radiación térmica es la emisión de ondas electromagnéticas por un cuerpo caliente que no necesita medio material para propagarse'),
('fisica', 'bachillerato', '{1}', 'La presión de un gas es la fuerza que ejercen las moléculas al chocar contra las paredes del recipiente dividida entre su superficie'),
('fisica', 'bachillerato', '{1}', 'La teoría cinética de los gases explica las propiedades macroscópicas de los gases a partir del movimiento aleatorio de sus moléculas'),
('fisica', 'bachillerato', '{1}', 'La ley de Boyle establece que a temperatura constante el producto de la presión por el volumen de un gas es constante'),
('fisica', 'bachillerato', '{1}', 'La ley de Charles establece que a presión constante el volumen de un gas es directamente proporcional a su temperatura absoluta'),
('fisica', 'bachillerato', '{1}', 'La ley de Gay-Lussac indica que a volumen constante la presión de un gas es directamente proporcional a su temperatura absoluta'),
('fisica', 'bachillerato', '{1}', 'El principio de conservación de la energía establece que la energía no se crea ni se destruye solo se transforma de una forma a otra'),
('fisica', 'bachillerato', '{1}', 'La ondulación es la propagación de una perturbación a través del medio sin que exista transporte neto de materia'),
('fisica', 'bachillerato', '{1}', 'Las ondas transversales vibran perpendicularmente a la dirección de propagación mientras que las longitudinales vibran en la misma dirección'),
('fisica', 'bachillerato', '{1}', 'La longitud de onda es la distancia entre dos puntos consecutivos que vibran en la misma fase de la perturbación'),
('fisica', 'bachillerato', '{1}', 'La velocidad de propagación de una onda es el producto de la frecuencia por la longitud de onda del movimiento ondulatorio'),
('fisica', 'bachillerato', '{1}', 'Las ondas estacionarias se forman por la superposición de dos ondas de igual frecuencia y amplitud que viajan en sentidos opuestos'),
('fisica', 'bachillerato', '{1}', 'El efecto Doppler consiste en el cambio de frecuencia percibida cuando la fuente emisora y el observador se mueven relativamente'),
('fisica', 'bachillerato', '{1}', 'La intensidad del sonido disminuye con el cuadrado de la distancia a la fuente al repartirse la energía en una superficie mayor'),
('fisica', 'bachillerato', '{1}', 'La resonancia se produce cuando la frecuencia de una fuerza periódica coincide con la frecuencia natural de oscilación del sistema'),
('fisica', 'bachillerato', '{1}', 'La difracción es el fenómeno por el cual las ondas rodean obstáculos o se abren al pasar por una rendija estrecha'),
('fisica', 'bachillerato', '{1}', 'El principio de superposición establece que cuando dos ondas coinciden en un punto su desplazamiento es la suma de ambas perturbaciones'),
('fisica', 'bachillerato', '{1}', 'La presión hidrostática en un fluido en reposo aumenta con la profundidad y depende de la densidad del fluido y la gravedad'),
('fisica', 'bachillerato', '{1}', 'El principio de Arquímedes establece que un cuerpo sumergido experimenta un empuje vertical hacia arriba igual al peso del fluido desalojado'),
('fisica', 'bachillerato', '{1}', 'El principio de Pascal afirma que la presión aplicada a un fluido confinado se transmite por igual en todas las direcciones'),
('fisica', 'bachillerato', '{1}', 'La ecuación de continuidad en un fluido ideal establece que el caudal es constante y el producto de sección por velocidad no varía'),
('fisica', 'bachillerato', '{1}', 'El teorema de Bernoulli relaciona la presión la velocidad y la altura en un fluido ideal en régimen estacionario'),
('fisica', 'bachillerato', '{1}', 'El centro de masas de un sistema es el punto donde se puede considerar concentrada toda la masa para estudiar su movimiento global'),
('fisica', 'bachillerato', '{1}', 'El momento de inercia de un cuerpo depende de la distribución de su masa respecto al eje de rotación considerado'),
('fisica', 'bachillerato', '{1}', 'El momento angular de un cuerpo rígido es el producto de su momento de inercia por su velocidad angular de rotación'),
('fisica', 'bachillerato', '{1}', 'El par de fuerzas o momento de torsión es el producto de la fuerza por la distancia perpendicular al eje de giro'),
('fisica', 'bachillerato', '{1}', 'Un cuerpo rígido está en equilibrio estático cuando la suma de fuerzas y la suma de momentos respecto a cualquier punto son cero');
INSERT INTO ordena_frases (subject_id, level, grades, sentence) VALUES
('fisica', 'bachillerato', '{2}', 'El campo eléctrico en un punto es la fuerza que experimentaría una carga positiva unitaria situada en ese punto del espacio'),
('fisica', 'bachillerato', '{2}', 'Las líneas de campo eléctrico salen de las cargas positivas y llegan a las negativas indicando la dirección del campo'),
('fisica', 'bachillerato', '{2}', 'El potencial eléctrico en un punto es el trabajo por unidad de carga necesario para traer una carga desde el infinito hasta ese punto'),
('fisica', 'bachillerato', '{2}', 'Las superficies equipotenciales son aquellas donde el potencial eléctrico tiene el mismo valor y son perpendiculares a las líneas de campo'),
('fisica', 'bachillerato', '{2}', 'La energía almacenada en un condensador es la mitad del producto de su capacidad por el cuadrado del voltaje entre sus placas'),
('fisica', 'bachillerato', '{2}', 'La capacidad de un condensador de placas paralelas es proporcional al área de las placas e inversamente proporcional a la distancia entre ellas'),
('fisica', 'bachillerato', '{2}', 'El flujo eléctrico a través de una superficie cerrada es proporcional a la carga neta encerrada según el teorema de Gauss'),
('fisica', 'bachillerato', '{2}', 'La corriente eléctrica es el flujo de cargas eléctricas a través de un conductor y se mide en amperios'),
('fisica', 'bachillerato', '{2}', 'La resistividad de un material mide su oposición intrínseca al paso de la corriente eléctrica y depende de la temperatura'),
('fisica', 'bachillerato', '{2}', 'La potencia disipada en una resistencia es igual al producto de la intensidad al cuadrado por la resistencia según el efecto Joule'),
('fisica', 'bachillerato', '{2}', 'Las leyes de Kirchhoff permiten analizar circuitos complejos estableciendo la conservación de la carga en nodos y la energía en mallas'),
('fisica', 'bachillerato', '{2}', 'El campo magnético creado por un conductor rectilíneo es proporcional a la intensidad e inversamente proporcional a la distancia al conductor'),
('fisica', 'bachillerato', '{2}', 'La fuerza de Lorentz es la fuerza que experimenta una carga en movimiento dentro de un campo magnético perpendicular a su velocidad'),
('fisica', 'bachillerato', '{2}', 'Un solenoide es una bobina cilíndrica que genera un campo magnético uniforme en su interior proporcional al número de espiras y a la corriente'),
('fisica', 'bachillerato', '{2}', 'La ley de Ampère relaciona la circulación del campo magnético a lo largo de un camino cerrado con la corriente que lo atraviesa'),
('fisica', 'bachillerato', '{2}', 'La inducción electromagnética genera una corriente eléctrica en un conductor cuando varía el flujo magnético que lo atraviesa'),
('fisica', 'bachillerato', '{2}', 'La ley de Lenz establece que la corriente inducida se opone siempre a la causa que la produce conservando la energía del sistema'),
('fisica', 'bachillerato', '{2}', 'La autoinducción se produce cuando la variación de corriente en una bobina genera una fuerza electromotriz inducida en ella misma'),
('fisica', 'bachillerato', '{2}', 'Un transformador modifica el voltaje alterno manteniendo la potencia constante mediante dos bobinas con diferente número de espiras'),
('fisica', 'bachillerato', '{2}', 'La corriente alterna se genera mediante la rotación de una espira en un campo magnético uniforme produciendo una señal sinusoidal'),
('fisica', 'bachillerato', '{2}', 'La impedancia en un circuito de corriente alterna combina la resistencia la reactancia capacitiva y la reactancia inductiva'),
('fisica', 'bachillerato', '{2}', 'El espectro electromagnético abarca desde las ondas de radio hasta los rayos gamma ordenados por frecuencia y longitud de onda'),
('fisica', 'bachillerato', '{2}', 'La velocidad de la luz en el vacío es una constante universal de aproximadamente trescientos mil kilómetros por segundo'),
('fisica', 'bachillerato', '{2}', 'La reflexión de la luz se rige por la ley que establece que el ángulo de incidencia es igual al ángulo de reflexión'),
('fisica', 'bachillerato', '{2}', 'La refracción se produce cuando la luz cambia de medio y su velocidad se modifica provocando un cambio en la dirección de propagación'),
('fisica', 'bachillerato', '{2}', 'La reflexión total interna ocurre cuando la luz pasa de un medio más denso a uno menos denso con un ángulo mayor que el crítico'),
('fisica', 'bachillerato', '{2}', 'Las lentes convergentes concentran los rayos de luz paralelos en un punto llamado foco real situado detrás de la lente'),
('fisica', 'bachillerato', '{2}', 'Las lentes divergentes separan los rayos de luz paralelos haciendo que parezcan proceder de un foco virtual situado delante de la lente'),
('fisica', 'bachillerato', '{2}', 'La ecuación de las lentes delgadas relaciona la distancia focal con las distancias del objeto y la imagen respecto a la lente'),
('fisica', 'bachillerato', '{2}', 'Los espejos cóncavos forman imágenes reales e invertidas cuando el objeto se sitúa más allá del centro de curvatura del espejo'),
('fisica', 'bachillerato', '{2}', 'La dispersión de la luz blanca por un prisma demuestra que está compuesta por diferentes longitudes de onda correspondientes a distintos colores'),
('fisica', 'bachillerato', '{2}', 'La difracción de la luz por una rendija simple produce un patrón de franjas claras y oscuras cuya anchura depende de la longitud de onda'),
('fisica', 'bachillerato', '{2}', 'El experimento de Young con doble rendija demostró la naturaleza ondulatoria de la luz al producir un patrón de interferencia'),
('fisica', 'bachillerato', '{2}', 'La polarización de la luz demuestra su naturaleza transversal al restringir la vibración del campo eléctrico a un solo plano'),
('fisica', 'bachillerato', '{2}', 'La radiación del cuerpo negro y la catástrofe ultravioleta llevaron a Planck a proponer la cuantización de la energía'),
('fisica', 'bachillerato', '{2}', 'La hipótesis de Planck establece que la energía se emite y absorbe en paquetes discretos llamados cuantos proporcionales a la frecuencia'),
('fisica', 'bachillerato', '{2}', 'El efecto fotoeléctrico fue explicado por Einstein al considerar que la luz está formada por fotones con energía igual a h por la frecuencia'),
('fisica', 'bachillerato', '{2}', 'La función de trabajo es la energía mínima necesaria para arrancar un electrón de la superficie de un metal por efecto fotoeléctrico'),
('fisica', 'bachillerato', '{2}', 'El modelo atómico de Bohr propone que los electrones orbitan en niveles de energía cuantizados y emiten fotones al cambiar de nivel'),
('fisica', 'bachillerato', '{2}', 'Los espectros de emisión atómicos son discontinuos porque los electrones solo pueden realizar transiciones entre niveles de energía discretos'),
('fisica', 'bachillerato', '{2}', 'La ecuación de De Broglie asigna una longitud de onda a toda partícula con momento lineal estableciendo la dualidad onda-partícula'),
('fisica', 'bachillerato', '{2}', 'Los orbitales atómicos son funciones de onda que describen la probabilidad de encontrar un electrón en una región del espacio'),
('fisica', 'bachillerato', '{2}', 'El principio de exclusión de Pauli establece que dos electrones de un átomo no pueden tener los cuatro números cuánticos iguales'),
('fisica', 'bachillerato', '{2}', 'La fusión nuclear consiste en la unión de núcleos ligeros para formar uno más pesado liberando enormes cantidades de energía'),
('fisica', 'bachillerato', '{2}', 'La equivalencia masa-energía de Einstein expresada como E igual a mc al cuadrado establece que masa y energía son intercambiables'),
('fisica', 'bachillerato', '{2}', 'La desintegración radiactiva alfa emite un núcleo de helio y reduce el número atómico en dos y el másico en cuatro'),
('fisica', 'bachillerato', '{2}', 'La desintegración beta menos convierte un neutrón en un protón emitiendo un electrón y un antineutrino del electrón'),
('fisica', 'bachillerato', '{2}', 'La radiación gamma es emisión de fotones de alta energía que acompaña a otras desintegraciones sin cambiar el número atómico ni el másico'),
('fisica', 'bachillerato', '{2}', 'El periodo de semidesintegración es el tiempo que tarda en desintegrarse la mitad de los núcleos radiactivos de una muestra'),
('fisica', 'bachillerato', '{2}', 'La ley de desintegración radiactiva describe el decrecimiento exponencial del número de núcleos radiactivos con el tiempo'),
('fisica', 'bachillerato', '{2}', 'La energía de enlace nuclear por nucleón alcanza su máximo en el hierro lo que explica que la fusión y la fisión liberen energía'),
('fisica', 'bachillerato', '{2}', 'El defecto de masa es la diferencia entre la masa de los nucleones por separado y la masa del núcleo que forman juntos'),
('fisica', 'bachillerato', '{2}', 'La fuerza nuclear fuerte mantiene unidos a los nucleones en el núcleo superando la repulsión eléctrica entre protones a distancias cortas'),
('fisica', 'bachillerato', '{2}', 'Los aceleradores de partículas permiten estudiar la estructura fundamental de la materia colisionando partículas a velocidades cercanas a la luz'),
('fisica', 'bachillerato', '{2}', 'El modelo estándar de partículas clasifica las partículas elementales en quarks leptones y bosones mediadores de las fuerzas fundamentales'),
('fisica', 'bachillerato', '{2}', 'Los quarks son partículas elementales con carga fraccionaria que se combinan en tripletes para formar protones y neutrones'),
('fisica', 'bachillerato', '{2}', 'El bosón de Higgs es la partícula responsable de conferir masa a las partículas elementales mediante el mecanismo de Higgs'),
('fisica', 'bachillerato', '{2}', 'La relatividad especial establece que las leyes de la física son iguales para todos los observadores inerciales y la velocidad de la luz es constante'),
('fisica', 'bachillerato', '{2}', 'La dilatación temporal indica que un reloj en movimiento respecto a un observador marca el tiempo más lentamente que un reloj en reposo'),
('fisica', 'bachillerato', '{2}', 'La contracción de la longitud predice que un objeto en movimiento se acorta en la dirección del movimiento según el factor de Lorentz'),
('fisica', 'bachillerato', '{2}', 'La relatividad general describe la gravedad como una curvatura del espacio-tiempo producida por la presencia de masa y energía'),
('fisica', 'bachillerato', '{2}', 'Las ondas gravitacionales son perturbaciones del espacio-tiempo que se propagan a la velocidad de la luz predichas por Einstein'),
('fisica', 'bachillerato', '{2}', 'El efecto túnel cuántico permite que una partícula atraviese una barrera de potencial aunque no tenga energía clásica suficiente para superarla'),
('fisica', 'bachillerato', '{2}', 'La energía de un fotón es directamente proporcional a su frecuencia e inversamente proporcional a su longitud de onda'),
('fisica', 'bachillerato', '{2}', 'El espín es una propiedad cuántica intrínseca de las partículas que no tiene equivalente clásico pero genera un momento magnético'),
('fisica', 'bachillerato', '{2}', 'La superconductividad es un fenómeno cuántico en el que ciertos materiales pierden toda resistencia eléctrica por debajo de una temperatura crítica'),
('fisica', 'bachillerato', '{2}', 'El efecto Compton demuestra la naturaleza corpuscular de la radiación al observar el cambio de longitud de onda en fotones dispersados por electrones'),
('fisica', 'bachillerato', '{2}', 'La relación entre campo eléctrico y potencial indica que el campo apunta en la dirección de máxima disminución del potencial eléctrico'),
('fisica', 'bachillerato', '{2}', 'La energía potencial eléctrica de dos cargas puntuales es proporcional al producto de las cargas e inversamente proporcional a su distancia'),
('fisica', 'bachillerato', '{2}', 'La fuerza entre dos conductores paralelos con corriente en el mismo sentido es atractiva según la ley de fuerzas de Ampère'),
('fisica', 'bachillerato', '{2}', 'El flujo magnético a través de una superficie es el producto escalar del campo magnético por el vector área de dicha superficie'),
('fisica', 'bachillerato', '{2}', 'La reluctancia magnética es la oposición de un material al paso del flujo magnético análoga a la resistencia en circuitos eléctricos'),
('fisica', 'bachillerato', '{2}', 'Los materiales ferromagnéticos como el hierro amplifican el campo magnético externo al alinear sus dominios magnéticos internos'),
('fisica', 'bachillerato', '{2}', 'La velocidad de fase de una onda electromagnética en un medio es el cociente entre la velocidad de la luz y el índice de refracción'),
('fisica', 'bachillerato', '{2}', 'El poder de resolución de un instrumento óptico determina su capacidad para distinguir dos puntos cercanos y está limitado por la difracción'),
('fisica', 'bachillerato', '{2}', 'La datación radiactiva utiliza el periodo de semidesintegración de isótopos como el carbono catorce para determinar la edad de muestras antiguas'),
('fisica', 'bachillerato', '{2}', 'La antimateria está formada por antipartículas con la misma masa pero carga opuesta que al aniquilarse con materia liberan energía pura'),
('fisica', 'bachillerato', '{2}', 'Las cuatro fuerzas fundamentales de la naturaleza son la gravitatoria la electromagnética la nuclear fuerte y la nuclear débil'),
('fisica', 'bachillerato', '{2}', 'La constante de estructura fina cuantifica la intensidad de la interacción electromagnética entre partículas cargadas y fotones'),
('fisica', 'bachillerato', '{2}', 'Los rayos X se producen cuando electrones acelerados impactan contra un blanco metálico emitiendo radiación de alta frecuencia'),
('fisica', 'bachillerato', '{2}', 'El láser genera luz coherente monocromática y direccional mediante la emisión estimulada de fotones en un medio activo'),
('fisica', 'bachillerato', '{2}', 'La fibra óptica transmite información mediante pulsos de luz que sufren reflexión total interna en su núcleo de vidrio'),
('fisica', 'bachillerato', '{2}', 'La termodinámica del universo sugiere que la entropía total aumenta constantemente conduciendo hacia un estado de máximo desorden'),
('fisica', 'bachillerato', '{2}', 'La constante de Planck reducida aparece en la ecuación de Schrödinger que describe la evolución temporal de los estados cuánticos de un sistema'),
('fisica', 'bachillerato', '{2}', 'El principio de superposición cuántica establece que un sistema puede existir en múltiples estados simultáneamente hasta que se realiza una medición');
INSERT INTO ordena_frases (subject_id, level, grades, sentence) VALUES
('matematicas', 'bachillerato', '{1}', 'Una matriz cuadrada es invertible si y solo si su determinante es distinto de cero y existe una única matriz inversa'),
('matematicas', 'bachillerato', '{1}', 'El determinante de una matriz se puede calcular desarrollando por los elementos de cualquier fila o columna usando adjuntos'),
('matematicas', 'bachillerato', '{1}', 'La matriz traspuesta se obtiene intercambiando las filas por las columnas de la matriz original manteniendo el mismo determinante'),
('matematicas', 'bachillerato', '{1}', 'Una matriz simétrica es aquella que coincide con su traspuesta y sus elementos cumplen que a sub ij es igual a a sub ji'),
('matematicas', 'bachillerato', '{1}', 'La matriz identidad es la matriz cuadrada con unos en la diagonal principal y ceros en el resto de posiciones'),
('matematicas', 'bachillerato', '{1}', 'El producto de matrices se define multiplicando cada fila de la primera por cada columna de la segunda y sumando los productos'),
('matematicas', 'bachillerato', '{1}', 'Un sistema de ecuaciones lineales se puede expresar en forma matricial como el producto de la matriz de coeficientes por el vector de incógnitas'),
('matematicas', 'bachillerato', '{1}', 'Un sistema de ecuaciones es compatible determinado cuando tiene una única solución e incompatible cuando no tiene ninguna'),
('matematicas', 'bachillerato', '{1}', 'Un sistema compatible indeterminado tiene infinitas soluciones que dependen de uno o más parámetros libres'),
('matematicas', 'bachillerato', '{1}', 'El método de Gauss transforma un sistema en otro equivalente escalonado mediante operaciones elementales de filas'),
('matematicas', 'bachillerato', '{1}', 'La propiedad de Sarrus permite calcular el determinante de una matriz tres por tres de forma rápida sumando y restando diagonales'),
('matematicas', 'bachillerato', '{1}', 'El menor complementario de un elemento es el determinante de la submatriz que resulta al eliminar su fila y su columna'),
('matematicas', 'bachillerato', '{1}', 'Las propiedades de los determinantes incluyen que se anulan si dos filas son proporcionales o si una fila es de ceros'),
('matematicas', 'bachillerato', '{1}', 'El radián es la unidad de medida angular que corresponde al ángulo central cuyo arco tiene la misma longitud que el radio'),
('matematicas', 'bachillerato', '{1}', 'La tangente de un ángulo se define como el cociente entre el seno y el coseno de dicho ángulo'),
('matematicas', 'bachillerato', '{1}', 'Las razones trigonométricas de la suma de ángulos permiten calcular el seno y coseno de alfa más beta a partir de las de cada ángulo'),
('matematicas', 'bachillerato', '{1}', 'Las fórmulas del ángulo doble expresan el seno y coseno de dos alfa en función del seno y coseno de alfa'),
('matematicas', 'bachillerato', '{1}', 'Las fórmulas del ángulo mitad permiten calcular las razones trigonométricas de alfa entre dos a partir de las del ángulo completo'),
('matematicas', 'bachillerato', '{1}', 'El teorema del seno establece que los lados de un triángulo son proporcionales a los senos de sus ángulos opuestos'),
('matematicas', 'bachillerato', '{1}', 'El teorema del coseno generaliza el teorema de Pitágoras para triángulos no rectángulos incorporando el coseno del ángulo entre dos lados'),
('matematicas', 'bachillerato', '{1}', 'La circunferencia goniométrica tiene radio uno y centro en el origen y permite representar las razones trigonométricas de cualquier ángulo'),
('matematicas', 'bachillerato', '{1}', 'Las ecuaciones trigonométricas se resuelven reduciendo la expresión a una sola razón y encontrando los ángulos que la satisfacen'),
('matematicas', 'bachillerato', '{1}', 'La función seno es periódica con periodo dos pi y oscila entre menos uno y uno alcanzando máximos y mínimos alternadamente'),
('matematicas', 'bachillerato', '{1}', 'La función coseno es la misma que la función seno desplazada pi medios hacia la izquierda en el eje horizontal'),
('matematicas', 'bachillerato', '{1}', 'El dominio de una función es el conjunto de valores de la variable independiente para los que la función está definida'),
('matematicas', 'bachillerato', '{1}', 'El recorrido o imagen de una función es el conjunto de todos los valores que toma la variable dependiente'),
('matematicas', 'bachillerato', '{1}', 'Una función es inyectiva si a cada imagen le corresponde un único elemento del dominio y nunca toma el mismo valor dos veces'),
('matematicas', 'bachillerato', '{1}', 'La composición de funciones aplica primero la función interior y después la exterior al resultado obtenido'),
('matematicas', 'bachillerato', '{1}', 'La función inversa existe cuando la función original es biyectiva y se obtiene despejando la variable independiente'),
('matematicas', 'bachillerato', '{1}', 'Las funciones exponenciales tienen la variable en el exponente y crecen muy rápidamente cuando la base es mayor que uno'),
('matematicas', 'bachillerato', '{1}', 'Las funciones logarítmicas son las inversas de las exponenciales y crecen lentamente a medida que aumenta la variable'),
('matematicas', 'bachillerato', '{1}', 'La función logaritmo transforma productos en sumas y cocientes en restas lo que simplifica cálculos con números muy grandes'),
('matematicas', 'bachillerato', '{1}', 'Una función polinómica de grado n tiene como máximo n raíces reales contando cada una con su multiplicidad correspondiente'),
('matematicas', 'bachillerato', '{1}', 'Una función racional es el cociente de dos polinomios y puede tener asíntotas verticales donde se anula el denominador'),
('matematicas', 'bachillerato', '{1}', 'La asíntota horizontal de una función racional se determina calculando el límite de la función cuando x tiende a infinito'),
('matematicas', 'bachillerato', '{1}', 'Una asíntota oblicua aparece cuando el grado del numerador supera en uno al del denominador en una función racional'),
('matematicas', 'bachillerato', '{1}', 'El cálculo de límites laterales permite determinar si una función tiene un límite en un punto o si existe una discontinuidad'),
('matematicas', 'bachillerato', '{1}', 'Las indeterminaciones del tipo cero entre cero se resuelven factorizando numerador y denominador y simplificando el factor común'),
('matematicas', 'bachillerato', '{1}', 'La indeterminación infinito entre infinito en funciones racionales se resuelve dividiendo numerador y denominador por la mayor potencia'),
('matematicas', 'bachillerato', '{1}', 'Una función continua no tiene saltos cortes ni agujeros en su gráfica y se puede dibujar sin levantar el lápiz del papel'),
('matematicas', 'bachillerato', '{1}', 'La discontinuidad evitable se produce cuando el límite existe pero no coincide con el valor de la función o la función no está definida'),
('matematicas', 'bachillerato', '{1}', 'La discontinuidad de salto finito ocurre cuando los límites laterales existen pero son diferentes y la función da un salto'),
('matematicas', 'bachillerato', '{1}', 'La derivada de un producto de funciones es la primera por la derivada de la segunda más la segunda por la derivada de la primera'),
('matematicas', 'bachillerato', '{1}', 'La derivada de un cociente de funciones se calcula con la fórmula del denominador por la derivada del numerador menos numerador por derivada del denominador'),
('matematicas', 'bachillerato', '{1}', 'Los máximos y mínimos relativos de una función se encuentran donde la derivada se anula y cambia de signo'),
('matematicas', 'bachillerato', '{1}', 'Si la segunda derivada es positiva en un punto crítico entonces la función presenta un mínimo relativo en ese punto'),
('matematicas', 'bachillerato', '{1}', 'Si la segunda derivada es negativa en un punto crítico entonces la función presenta un máximo relativo en ese punto'),
('matematicas', 'bachillerato', '{1}', 'La monotonía de una función indica los intervalos donde es creciente con derivada positiva o decreciente con derivada negativa'),
('matematicas', 'bachillerato', '{1}', 'La concavidad de una función se analiza mediante la segunda derivada que indica si la curva se abre hacia arriba o hacia abajo'),
('matematicas', 'bachillerato', '{1}', 'La recta tangente a una curva en un punto tiene como pendiente el valor de la derivada de la función evaluada en ese punto'),
('matematicas', 'bachillerato', '{1}', 'El teorema de Rolle establece que si una función continua vale igual en los extremos de un intervalo su derivada se anula en algún punto interior'),
('matematicas', 'bachillerato', '{1}', 'El teorema del valor medio de Lagrange garantiza un punto donde la pendiente de la tangente iguala a la pendiente de la secante entre los extremos'),
('matematicas', 'bachillerato', '{1}', 'La optimización de funciones consiste en encontrar el valor máximo o mínimo de una magnitud sujeta a ciertas restricciones del problema'),
('matematicas', 'bachillerato', '{1}', 'La sucesión de Fibonacci se construye sumando los dos términos anteriores y aparece en numerosos fenómenos naturales y matemáticos'),
('matematicas', 'bachillerato', '{1}', 'Una sucesión convergente tiene un límite finito al que se aproximan sus términos cuando el índice crece indefinidamente'),
('matematicas', 'bachillerato', '{1}', 'Una progresión aritmética tiene diferencia constante entre términos consecutivos y su suma parcial se calcula con la fórmula de Gauss'),
('matematicas', 'bachillerato', '{1}', 'Una progresión geométrica tiene razón constante entre términos consecutivos y su suma infinita converge si la razón es menor que uno en valor absoluto'),
('matematicas', 'bachillerato', '{1}', 'El número e se define como el límite de la sucesión uno más uno entre n elevado a n cuando n tiende a infinito'),
('matematicas', 'bachillerato', '{1}', 'La inecuación lineal se resuelve como una ecuación pero al multiplicar o dividir por un número negativo se invierte el sentido de la desigualdad'),
('matematicas', 'bachillerato', '{1}', 'La función valor absoluto de x vale x cuando x es positivo y menos x cuando x es negativo con vértice en el origen'),
('matematicas', 'bachillerato', '{1}', 'Las transformaciones de funciones incluyen traslaciones reflexiones dilataciones y compresiones que modifican su gráfica de forma predecible'),
('matematicas', 'bachillerato', '{1}', 'La paridad de una función se determina verificando si es simétrica respecto al eje vertical para funciones pares o al origen para impares'),
('matematicas', 'bachillerato', '{1}', 'Los números complejos extienden los números reales añadiendo la unidad imaginaria i cuyo cuadrado es igual a menos uno'),
('matematicas', 'bachillerato', '{1}', 'La forma polar de un número complejo lo expresa mediante su módulo y su argumento facilitando la multiplicación y la potenciación'),
('matematicas', 'bachillerato', '{1}', 'El producto escalar de dos vectores se calcula multiplicando sus componentes correspondientes y sumando los resultados'),
('matematicas', 'bachillerato', '{1}', 'La ecuación de la recta en forma general es ax más by más c igual a cero donde a y b no son simultáneamente cero'),
('matematicas', 'bachillerato', '{1}', 'La distancia entre dos puntos del plano se calcula como la raíz cuadrada de la suma de los cuadrados de las diferencias de coordenadas'),
('matematicas', 'bachillerato', '{1}', 'La ecuación de la circunferencia con centro en h k y radio r se escribe como x menos h al cuadrado más y menos k al cuadrado igual a r cuadrado'),
('matematicas', 'bachillerato', '{1}', 'Dos rectas son paralelas cuando tienen la misma pendiente y son perpendiculares cuando el producto de sus pendientes es menos uno'),
('matematicas', 'bachillerato', '{1}', 'Las cónicas son curvas que resultan de la intersección de un plano con un cono y pueden ser elipses parábolas o hipérbolas'),
('matematicas', 'bachillerato', '{1}', 'La combinatoria estudia las formas de agrupar elementos mediante permutaciones variaciones y combinaciones con o sin repetición'),
('matematicas', 'bachillerato', '{1}', 'El factorial de un número natural n es el producto de todos los enteros positivos desde uno hasta n'),
('matematicas', 'bachillerato', '{1}', 'La probabilidad condicionada mide la probabilidad de un suceso sabiendo que otro suceso ya ha ocurrido previamente'),
('matematicas', 'bachillerato', '{1}', 'Dos sucesos son independientes cuando la ocurrencia de uno no afecta a la probabilidad de que ocurra el otro'),
('matematicas', 'bachillerato', '{1}', 'El diagrama de árbol permite visualizar todas las ramas de un experimento compuesto y calcular probabilidades multiplicando por las ramas'),
('matematicas', 'bachillerato', '{1}', 'La media aritmética es la suma de todos los datos dividida entre el número total de observaciones de la muestra'),
('matematicas', 'bachillerato', '{1}', 'La mediana es el valor central de un conjunto de datos ordenados que deja la misma cantidad de valores a cada lado'),
('matematicas', 'bachillerato', '{1}', 'La desviación típica es la raíz cuadrada de la varianza y mide la dispersión de los datos en las mismas unidades que la variable'),
('matematicas', 'bachillerato', '{1}', 'El binomio de Newton permite desarrollar la potencia de una suma en términos de combinaciones y potencias de cada sumando'),
('matematicas', 'bachillerato', '{1}', 'Los sistemas de inecuaciones lineales definen regiones factibles en el plano cuyas soluciones son los puntos de la intersección de semiplanos'),
('matematicas', 'bachillerato', '{1}', 'La programación lineal busca optimizar una función objetivo sujeta a restricciones lineales evaluando los vértices de la región factible'),
('matematicas', 'bachillerato', '{1}', 'Las funciones definidas a trozos se expresan con distintas expresiones analíticas según el intervalo del dominio considerado'),
('matematicas', 'bachillerato', '{1}', 'La derivada de la función exponencial de base e es ella misma lo que la convierte en una función fundamental del cálculo'),
('matematicas', 'bachillerato', '{1}', 'La derivada del logaritmo neperiano de x es uno entre x y se utiliza frecuentemente en cálculos de integración y derivación'),
('matematicas', 'bachillerato', '{1}', 'El polinomio de Taylor aproxima una función derivable en un entorno de un punto mediante una suma de potencias de x menos a');
INSERT INTO ordena_frases (subject_id, level, grades, sentence) VALUES
('matematicas', 'bachillerato', '{2}', 'La integral indefinida de una función es el conjunto de todas sus primitivas que difieren entre sí en una constante aditiva'),
('matematicas', 'bachillerato', '{2}', 'La integración por sustitución consiste en cambiar la variable de integración para transformar el integrando en una expresión más sencilla'),
('matematicas', 'bachillerato', '{2}', 'La integración de funciones racionales se realiza descomponiendo la fracción en fracciones simples con denominadores irreducibles'),
('matematicas', 'bachillerato', '{2}', 'La regla de Barrow permite calcular la integral definida evaluando una primitiva del integrando en los extremos del intervalo'),
('matematicas', 'bachillerato', '{2}', 'El área entre dos curvas se calcula integrando el valor absoluto de la diferencia de las funciones en el intervalo correspondiente'),
('matematicas', 'bachillerato', '{2}', 'El volumen de un sólido de revolución se calcula integrando pi por el cuadrado de la función al girar alrededor del eje correspondiente'),
('matematicas', 'bachillerato', '{2}', 'El teorema del valor medio integral garantiza la existencia de un punto donde la función alcanza el valor medio de la integral'),
('matematicas', 'bachillerato', '{2}', 'Las integrales impropias extienden el concepto de integral definida a intervalos infinitos o funciones con discontinuidades'),
('matematicas', 'bachillerato', '{2}', 'La convergencia de una integral impropia se determina calculando el límite de la integral definida cuando el extremo tiende a infinito'),
('matematicas', 'bachillerato', '{2}', 'El teorema de Weierstrass garantiza que toda función continua en un intervalo cerrado alcanza un máximo absoluto y un mínimo absoluto'),
('matematicas', 'bachillerato', '{2}', 'La regla de L''Hôpital permite resolver indeterminaciones del tipo cero entre cero o infinito entre infinito derivando numerador y denominador'),
('matematicas', 'bachillerato', '{2}', 'La continuidad uniforme implica que el mismo épsilon sirve para todos los puntos del dominio independientemente de su localización'),
('matematicas', 'bachillerato', '{2}', 'El estudio completo de una función incluye dominio simetría cortes con los ejes asíntotas monotonía extremos curvatura e inflexiones'),
('matematicas', 'bachillerato', '{2}', 'La matriz adjunta se obtiene sustituyendo cada elemento por su adjunto que es el cofactor con el signo correspondiente'),
('matematicas', 'bachillerato', '{2}', 'La inversa de una matriz se calcula dividiendo la traspuesta de la adjunta entre el determinante de la matriz original'),
('matematicas', 'bachillerato', '{2}', 'Las ecuaciones matriciales se resuelven despejando la matriz incógnita utilizando las propiedades del producto y la matriz inversa'),
('matematicas', 'bachillerato', '{2}', 'Un sistema homogéneo tiene siempre la solución trivial y admite soluciones no triviales si el determinante de la matriz de coeficientes es cero'),
('matematicas', 'bachillerato', '{2}', 'El teorema de Rouché-Frobenius establece que un sistema es compatible si y solo si los rangos de la matriz de coeficientes y la ampliada coinciden'),
('matematicas', 'bachillerato', '{2}', 'Un sistema con parámetros puede cambiar de tipo según los valores del parámetro pasando de determinado a indeterminado o incompatible'),
('matematicas', 'bachillerato', '{2}', 'La discusión de un sistema con parámetros requiere analizar los rangos de las matrices para cada valor posible del parámetro'),
('matematicas', 'bachillerato', '{2}', 'El producto vectorial de dos vectores da como resultado un vector perpendicular a ambos cuyo módulo es el área del paralelogramo formado'),
('matematicas', 'bachillerato', '{2}', 'El producto mixto de tres vectores calcula el volumen del paralelepípedo que forman y se anula si los vectores son coplanarios'),
('matematicas', 'bachillerato', '{2}', 'La ecuación paramétrica de una recta en el espacio se obtiene a partir de un punto y un vector director que indica su dirección'),
('matematicas', 'bachillerato', '{2}', 'La ecuación implícita de un plano es ax más by más cz más d igual a cero donde el vector normal es a b c'),
('matematicas', 'bachillerato', '{2}', 'Tres puntos no alineados determinan un único plano cuya ecuación se puede obtener mediante el producto vectorial de dos vectores del plano'),
('matematicas', 'bachillerato', '{2}', 'La distancia entre dos planos paralelos se calcula tomando un punto cualquiera de uno y hallando su distancia al otro plano'),
('matematicas', 'bachillerato', '{2}', 'La distancia entre dos rectas que se cruzan se calcula proyectando el vector que une sus puntos sobre el vector perpendicular común'),
('matematicas', 'bachillerato', '{2}', 'El ángulo entre dos rectas se calcula hallando el ángulo entre sus vectores directores mediante el producto escalar'),
('matematicas', 'bachillerato', '{2}', 'El ángulo entre una recta y un plano es el complementario del ángulo entre el vector director de la recta y el vector normal del plano'),
('matematicas', 'bachillerato', '{2}', 'La posición relativa de dos planos se determina estudiando la proporcionalidad de sus vectores normales y los términos independientes'),
('matematicas', 'bachillerato', '{2}', 'La posición relativa de recta y plano se analiza sustituyendo las ecuaciones paramétricas de la recta en la ecuación del plano'),
('matematicas', 'bachillerato', '{2}', 'El haz de planos que contiene a una recta se expresa como combinación lineal de las dos ecuaciones implícitas de la recta'),
('matematicas', 'bachillerato', '{2}', 'La esfera es el lugar geométrico de los puntos del espacio que equidistan de un punto fijo llamado centro con radio constante'),
('matematicas', 'bachillerato', '{2}', 'La distribución binomial modela el número de éxitos en n ensayos independientes con la misma probabilidad de éxito en cada uno'),
('matematicas', 'bachillerato', '{2}', 'La esperanza matemática de una variable aleatoria discreta es la suma de cada valor multiplicado por su probabilidad'),
('matematicas', 'bachillerato', '{2}', 'La varianza de una variable aleatoria mide la dispersión respecto a la media y es la esperanza del cuadrado de la desviación'),
('matematicas', 'bachillerato', '{2}', 'La distribución normal se caracteriza completamente por su media y su desviación típica que determinan su centro y su dispersión'),
('matematicas', 'bachillerato', '{2}', 'La tipificación transforma una variable normal cualquiera en una normal estándar con media cero y desviación típica uno'),
('matematicas', 'bachillerato', '{2}', 'La aproximación de la binomial por la normal se aplica cuando n es grande y la probabilidad no es extrema usando la corrección de continuidad'),
('matematicas', 'bachillerato', '{2}', 'El teorema central del límite establece que la media muestral se distribuye aproximadamente como una normal cuando la muestra es grande'),
('matematicas', 'bachillerato', '{2}', 'El nivel de confianza indica la probabilidad de que el intervalo construido contenga el verdadero valor del parámetro poblacional'),
('matematicas', 'bachillerato', '{2}', 'El tamaño muestral necesario para una estimación se calcula a partir del nivel de confianza y el error máximo admisible'),
('matematicas', 'bachillerato', '{2}', 'El error de estimación disminuye al aumentar el tamaño de la muestra siendo inversamente proporcional a la raíz cuadrada de n'),
('matematicas', 'bachillerato', '{2}', 'La proporción muestral es un estimador insesgado de la proporción poblacional y su distribución se aproxima a una normal para muestras grandes'),
('matematicas', 'bachillerato', '{2}', 'El muestreo aleatorio simple garantiza que todos los individuos de la población tienen la misma probabilidad de ser seleccionados'),
('matematicas', 'bachillerato', '{2}', 'El muestreo estratificado divide la población en subgrupos homogéneos y selecciona una muestra proporcional de cada estrato'),
('matematicas', 'bachillerato', '{2}', 'La covarianza mide la relación lineal entre dos variables y es positiva cuando ambas aumentan juntas y negativa cuando una sube y otra baja'),
('matematicas', 'bachillerato', '{2}', 'El contraste de hipótesis permite decidir si se rechaza o no una hipótesis sobre un parámetro poblacional a partir de datos muestrales'),
('matematicas', 'bachillerato', '{2}', 'El p-valor es la probabilidad de obtener un resultado tan extremo como el observado suponiendo que la hipótesis nula es cierta'),
('matematicas', 'bachillerato', '{2}', 'La tabla de la distribución normal estándar proporciona las probabilidades acumuladas bajo la curva de Gauss para valores positivos de z'),
('matematicas', 'bachillerato', '{2}', 'Los cuartiles dividen la distribución en cuatro partes iguales y el segundo cuartil coincide con la mediana de los datos'),
('matematicas', 'bachillerato', '{2}', 'El diagrama de caja y bigotes resume los cinco números clave de una distribución: mínimo primer cuartil mediana tercer cuartil y máximo'),
('matematicas', 'bachillerato', '{2}', 'La función de distribución acumulada de una variable aleatoria da la probabilidad de que la variable tome un valor menor o igual al dado'),
('matematicas', 'bachillerato', '{2}', 'La independencia de sucesos implica que la probabilidad de la intersección es igual al producto de las probabilidades individuales'),
('matematicas', 'bachillerato', '{2}', 'El problema de la ruina del jugador ilustra cómo las probabilidades y las rachas determinan el resultado final en juegos repetidos'),
('matematicas', 'bachillerato', '{2}', 'La integral de la función de densidad de una variable continua sobre todo su dominio debe ser igual a uno para ser válida'),
('matematicas', 'bachillerato', '{2}', 'Las derivadas parciales miden la tasa de cambio de una función de varias variables respecto a una variable manteniendo las demás constantes'),
('matematicas', 'bachillerato', '{2}', 'La serie de Taylor centrada en cero se denomina serie de Maclaurin y aproxima funciones mediante polinomios de grado creciente'),
('matematicas', 'bachillerato', '{2}', 'El criterio de la razón permite determinar si una serie numérica converge o diverge comparando el cociente entre términos consecutivos'),
('matematicas', 'bachillerato', '{2}', 'La media ponderada asigna diferentes pesos a cada dato según su importancia relativa antes de calcular el promedio'),
('matematicas', 'bachillerato', '{2}', 'El coeficiente de variación es el cociente entre la desviación típica y la media y permite comparar la dispersión de distribuciones diferentes'),
('matematicas', 'bachillerato', '{2}', 'Las variables aleatorias continuas tienen una función de densidad cuya integral en un intervalo da la probabilidad de que la variable caiga en él'),
('matematicas', 'bachillerato', '{2}', 'La distribución uniforme continua asigna la misma probabilidad a todos los intervalos de igual longitud dentro de su rango'),
('matematicas', 'bachillerato', '{2}', 'La propiedad reproductiva de la normal establece que la suma de variables normales independientes es también una variable normal'),
('matematicas', 'bachillerato', '{2}', 'La desigualdad de Chebyshev garantiza que al menos el setenta y cinco por ciento de los datos están a menos de dos desviaciones de la media'),
('matematicas', 'bachillerato', '{2}', 'El plano osculador de una curva en un punto contiene la tangente y la normal principal y es donde mejor se aproxima la curva localmente'),
('matematicas', 'bachillerato', '{2}', 'La proyección ortogonal de un vector sobre otro se calcula multiplicando el vector por el cociente del producto escalar entre el módulo al cuadrado'),
('matematicas', 'bachillerato', '{2}', 'El área de un triángulo en el espacio se calcula como la mitad del módulo del producto vectorial de dos de sus lados'),
('matematicas', 'bachillerato', '{2}', 'La ecuación continua de una recta en el espacio se obtiene igualando los cocientes de las coordenadas menos el punto entre las componentes del director'),
('matematicas', 'bachillerato', '{2}', 'El simétrico de un punto respecto a un plano se obtiene proyectando el punto sobre el plano y prolongando la misma distancia al otro lado'),
('matematicas', 'bachillerato', '{2}', 'La recta perpendicular común a dos rectas que se cruzan pasa por los puntos más cercanos entre ambas y es ortogonal a las dos'),
('matematicas', 'bachillerato', '{2}', 'El volumen de un tetraedro se calcula como un sexto del valor absoluto del producto mixto de tres aristas que parten del mismo vértice'),
('matematicas', 'bachillerato', '{2}', 'La fórmula de la distancia de un punto a una recta en el espacio utiliza el producto vectorial del director con el vector punto-recta'),
('matematicas', 'bachillerato', '{2}', 'Los eigenvalores de una matriz se obtienen resolviendo la ecuación característica que resulta de igualar el determinante de A menos lambda I a cero'),
('matematicas', 'bachillerato', '{2}', 'La diagonalización de una matriz permite expresarla como producto de la matriz de autovectores por la diagonal de autovalores por su inversa'),
('matematicas', 'bachillerato', '{2}', 'El método de eliminación gaussiana con pivoteo parcial mejora la estabilidad numérica al elegir el mayor elemento como pivote'),
('matematicas', 'bachillerato', '{2}', 'Las funciones implícitas definen relaciones entre variables sin despejar una en función de la otra y se derivan con la regla implícita'),
('matematicas', 'bachillerato', '{2}', 'La derivada de la función arco tangente de x es uno entre uno más x al cuadrado y se usa frecuentemente en cálculo integral'),
('matematicas', 'bachillerato', '{2}', 'La primitiva de uno entre x es el logaritmo neperiano del valor absoluto de x más la constante de integración'),
('matematicas', 'bachillerato', '{2}', 'La suma de Riemann aproxima el área bajo una curva dividiendo el intervalo en subintervalos y sumando las áreas de los rectángulos'),
('matematicas', 'bachillerato', '{2}', 'El cambio de variable trigonométrico simplifica integrales que contienen raíces cuadráticas sustituyendo x por expresiones con seno o tangente'),
('matematicas', 'bachillerato', '{2}', 'Las aplicaciones de la integral definida incluyen el cálculo de áreas volúmenes longitudes de arco y centros de masas'),
('matematicas', 'bachillerato', '{2}', 'La longitud de arco de una curva se calcula integrando la raíz cuadrada de uno más la derivada al cuadrado en el intervalo'),
('matematicas', 'bachillerato', '{2}', 'El criterio de la integral establece que una serie de términos positivos converge si y solo si la integral impropia correspondiente converge'),
('matematicas', 'bachillerato', '{2}', 'La fórmula de Leibniz permite derivar bajo el signo integral cuando los límites de integración dependen del parámetro de derivación');
INSERT INTO ordena_frases (subject_id, level, grades, sentence) VALUES
('quimica', 'bachillerato', '{2}', 'Los números cuánticos principal angular magnético y de espín describen completamente el estado de un electrón en un átomo'),
('quimica', 'bachillerato', '{2}', 'El principio de Aufbau indica que los electrones ocupan primero los orbitales de menor energía antes de llenar los de mayor energía'),
('quimica', 'bachillerato', '{2}', 'La regla de Hund establece que los electrones se distribuyen en orbitales degenerados con espines paralelos antes de emparejarse'),
('quimica', 'bachillerato', '{2}', 'El radio atómico disminuye a lo largo de un periodo de izquierda a derecha debido al aumento de la carga nuclear efectiva'),
('quimica', 'bachillerato', '{2}', 'La energía de ionización es la energía mínima necesaria para arrancar un electrón de un átomo gaseoso en su estado fundamental'),
('quimica', 'bachillerato', '{2}', 'La afinidad electrónica es la energía liberada cuando un átomo neutro gaseoso capta un electrón formando un anión monoatómico'),
